# file: test_calculator.py
import unittest
from calculator import add, subtract, multiply, divide, calculate

class TestCalculator(unittest.TestCase):
    def test_add(self): self.assertEqual(add(2, 3), 5)
    def test_subtract(self): self.assertEqual(subtract(10, 4), 6)
    def test_multiply(self): self.assertEqual(multiply(3, 4), 12)
    def test_divide(self): self.assertEqual(divide(10, 2), 5.0)
    def test_divide_by_zero(self):
        with self.assertRaises(ValueError): divide(5, 0)
    def test_calculate_add(self): self.assertEqual(calculate('+', 1, 2), 3)
    def test_calculate_unknown_op(self):
        with self.assertRaises(ValueError): calculate('%', 1, 2)

if __name__ == '__main__':
    unittest.main()
```

